// Extrair dados do webhook
const data = items[0].json;
const repoUrl = data.repo_url;
const provider = data.provider;
const branch = data.branch || 'main';
const accessToken = data.access_token;
const projectId = data.project_id;
const repoId = data.repo_id;
const callbackUrl = data.callback_url;

// Determinar API base
let apiBase = '';
let repoPath = '';
if (provider === 'github') {
  const match = repoUrl.match(/github\.com\/([^/]+)\/([^/]+)/);
  if (match) {
    repoPath = match[1] + '/' + match[2].replace('.git', '');
    apiBase = 'https://api.github.com';
  }
} else if (provider === 'gitlab') {
  const match = repoUrl.match(/gitlab\.com\/(.+?)(?:\.git)?$/);
  if (match) {
    repoPath = encodeURIComponent(match[1]);
    apiBase = 'https://gitlab.com/api/v4';
  }
} else if (provider === 'bitbucket') {
  const match = repoUrl.match(/bitbucket\.org\/([^/]+)\/([^/]+)/);
  if (match) {
    repoPath = match[1] + '/' + match[2].replace('.git', '');
    apiBase = 'https://api.bitbucket.org/2.0';
  }
}

return [{
  json: {
    ...data,
    apiBase,
    repoPath,
    projectId,
    repoId,
    callbackUrl,
    accessToken,
    branch
  }
}];

// Categorizar arquivos do repositório
const tree = items[0].json.tree || [];
const prevData = items[0].json;

const categories = {
  code: [],
  docs: [],
  config: [],
  ci_cd: [],
  tests: [],
  schema: []
};

const codeExts = ['py','ts','js','tsx','jsx','java','go','rs','cs','kt','rb','php','swift','cpp','c','h'];
const docExts = ['md','txt','rst'];
const configExts = ['yml','yaml','json','toml','ini','cfg'];
const schemaExts = ['sql','prisma'];
const skipDirs = ['node_modules','.git','dist','build','__pycache__','.next','vendor','.venv','venv'];
const skipExts = ['png','jpg','jpeg','gif','svg','ico','woff','woff2','ttf','eot','map','lock'];

for (const file of tree) {
  if (file.type !== 'blob') continue;
  const path = file.path;

  // Skip
  if (skipDirs.some(d => path.includes(d + '/'))) continue;
  const ext = path.split('.').pop().toLowerCase();
  if (skipExts.includes(ext)) continue;
  if (path.includes('package-lock') || path.includes('yarn.lock')) continue;

  // Categorizar
  if (path.includes('.github/workflows') || path.includes('.gitlab-ci') || path.includes('Jenkinsfile') || path.includes('.circleci')) {
    categories.ci_cd.push(path);
  } else if (path.includes('test') || path.includes('spec') || path.includes('__tests__')) {
    categories.tests.push(path);
  } else if (path.includes('migration') || schemaExts.includes(ext) || path.includes('alembic')) {
    categories.schema.push(path);
  } else if (path.toLowerCase().includes('readme') || path.toLowerCase().includes('changelog') || path.toLowerCase().includes('contributing') || path.toLowerCase().includes('license') || docExts.includes(ext)) {
    categories.docs.push(path);
  } else if (path.includes('Dockerfile') || path.includes('docker-compose') || configExts.includes(ext)) {
    categories.config.push(path);
  } else if (codeExts.includes(ext)) {
    categories.code.push(path);
  }
}

// Limitar cada categoria a 30 arquivos
const limited = {};
for (const [cat, files] of Object.entries(categories)) {
  limited[cat] = files.slice(0, 30);
}

const totalFiles = Object.values(categories).reduce((sum, files) => sum + files.length, 0);

// Criar um item por categoria não-vazia
const output = [];
for (const [category, files] of Object.entries(limited)) {
  if (files.length > 0) {
    output.push({
      json: {
        category,
        files,
        filesCount: files.length,
        totalFiles,
        projectId: prevData.projectId,
        repoId: prevData.repoId,
        repoUrl: prevData.repo_url || prevData.repoUrl,
        repoPath: prevData.repoPath,
        accessToken: prevData.accessToken,
        apiBase: prevData.apiBase,
        branch: prevData.branch,
        callbackUrl: prevData.callbackUrl
      }
    });
  }
}

return output;

