// Preparar documento para injetar no GCA
const prevData = items[0].json;
const response = prevData.choices ? prevData.choices[0].message.content : 'Análise não disponível';
const category = prevData.category || 'unknown';
const repoUrl = prevData.repoUrl || '';
const projectId = prevData.projectId;

return [{
  json: {
    projectId,
    category,
    repoUrl,
    content: response,
    filename: `repo-externo-${category}.md`,
    description: `Repositório externo: ${repoUrl} — ${category}`,
    callbackUrl: prevData.callbackUrl,
    repoId: prevData.repoId,
    totalFiles: prevData.totalFiles || 0,
    filesCount: prevData.filesCount || 0
  }
}];
